function checkToxin(battle, context) {
  const actor = context.sourcePiece;
  if (!actor) return { success: false };
  const tracers = battle.pieces.filter(p => p.templateId === 'tracer' && p.currentHp > 0);
  if (tracers.length === 0) return { success: false };
  let triggered = false;
  const messages = [];
  for (const tracer of tracers) {
    if (actor.ownerPlayerId === tracer.ownerPlayerId) continue;
    const enemies = battle.pieces.filter(p =>
      p.ownerPlayerId !== tracer.ownerPlayerId &&
      p.currentHp > 0 &&
      Math.max(Math.abs(p.x - tracer.x), Math.abs(p.y - tracer.y)) <= 2
    );
    if (enemies.length === 0) continue;
    const target = enemies[Math.floor(Math.random() * enemies.length)];
    const dmg = Math.max(0, tracer.attack - (target.defense || 0));
    target.currentHp = Math.max(0, target.currentHp - dmg);
    messages.push(`${tracer.name}脉冲手枪：对${target.name}造成${dmg}点伤害`);
    triggered = true;
  }
  return triggered ? { success: true, message: messages.join('，') } : { success: false };
}
